153: export interface FieldReducerInfo extends RegistryItem {
154:   // Internal details
155:   emptyInputResult?: unknown; // typically null, but some things like 'count' & 'sum' should be zero
156:   standard: boolean; // The most common stats can all be calculated in a single pass
157:   preservesUnits: boolean; // Whether this reducer preserves units, certain ones don't e.g. count, distinct count, etc,
