466: // Used for test cases
467: export const defaultCalcs: FieldCalcs = {
468:   sum: 0,
469:   max: -Number.MAX_VALUE,
470:   min: Number.MAX_VALUE,
471:   logmin: Number.MAX_VALUE,
472:   mean: null,
473:   last: null,
474:   first: null,
475:   lastNotNull: null,
476:   firstNotNull: null,
477:   count: 0,
478:   nonNullCount: 0,
479:   allIsNull: true,
480:   allIsZero: true,
481:   range: null,
482:   diff: null,
483:   delta: 0,
484:   step: Number.MAX_VALUE,
485:   diffperc: 0,
486:   // Just used for calculations -- not exposed as a stat
487:   previousDeltaUp: true,
488: };
489: 
490: export function doStandardCalcs(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
491:   const calcs: FieldCalcs = { ...defaultCalcs };
492: 
493:   const data = field.values;
494: 
495:   // early return for undefined / empty series
496:   if (!data) {
497:     return calcs;
498:   }
499: 
500:   const isNumberField = field.type === FieldType.number || field.type === FieldType.time;
501: 
502:   for (let i = 0; i < data.length; i++) {
503:     let currentValue = data[i];
504: 
505:     if (i === 0) {
506:       calcs.first = currentValue;
507:     }
508: 
509:     calcs.last = currentValue;
510: 
511:     if (currentValue == null) {
512:       if (ignoreNulls) {
513:         continue;
514:       }
515:       if (nullAsZero) {
516:         currentValue = 0;
517:       }
518:     }
519: 
520:     calcs.count++;
521: 
522:     if (currentValue != null && !Number.isNaN(currentValue)) {
523:       // null || undefined || NaN
524:       const isFirst = calcs.firstNotNull === null;
525:       if (isFirst) {
526:         calcs.firstNotNull = currentValue;
527:       }
528: 
529:       if (isNumberField) {
530:         calcs.sum += currentValue || 0;
531:         calcs.allIsNull = false;
532:         calcs.nonNullCount++;
533: 
534:         if (!isFirst) {
535:           const step = currentValue - calcs.lastNotNull!;
536:           if (calcs.step > step) {
537:             calcs.step = step; // the minimum interval
538:           }
539: 
540:           if (calcs.lastNotNull! > currentValue) {
541:             // counter reset
542:             calcs.previousDeltaUp = false;
543:           } else {
544:             if (calcs.previousDeltaUp) {
545:               calcs.delta += step; // normal increment
546:             }
547:             calcs.previousDeltaUp = true;
548:           }
549:         }
550: 
551:         if (currentValue > calcs.max) {
552:           calcs.max = currentValue;
553:         }
554: 
555:         if (currentValue < calcs.min) {
556:           calcs.min = currentValue;
557:         }
558: 
559:         if (currentValue < calcs.logmin && currentValue > 0) {
560:           calcs.logmin = currentValue;
561:         }
562:       }
563: 
564:       if (currentValue !== 0) {
565:         calcs.allIsZero = false;
566:       }
567: 
568:       calcs.lastNotNull = currentValue;
569:     }
570:   }
571: 
572:   if (calcs.max === -Number.MAX_VALUE) {
573:     calcs.max = null;
574:   }
575: 
576:   if (calcs.min === Number.MAX_VALUE) {
577:     calcs.min = null;
578:   }
579: 
580:   if (calcs.step === Number.MAX_VALUE) {
581:     calcs.step = null;
582:   }
583: 
584:   if (calcs.nonNullCount > 0) {
585:     calcs.mean = calcs.sum! / calcs.nonNullCount;
586:   }
587: 
588:   if (calcs.allIsNull) {
589:     calcs.allIsZero = false;
590:   }
591: 
592:   if (calcs.max !== null && calcs.min !== null) {
593:     calcs.range = calcs.max - calcs.min;
594:   }
595: 
596:   if (isNumber(calcs.firstNotNull) && isNumber(calcs.lastNotNull)) {
597:     calcs.diff = calcs.lastNotNull - calcs.firstNotNull;
598:   }
599: 
600:   if (isNumber(calcs.firstNotNull) && isNumber(calcs.diff)) {
601:     calcs.diffperc = (calcs.diff / calcs.firstNotNull) * 100;
602:   }
603: 
604:   return calcs;
605: }
